GameTicket = class()

function GameTicket:ctor(player)
    self.userId = player.userId
    self.gunTicket = {}
end

function GameTicket:init()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        self.gunTicket = player.gun_ticket
        self:saveData()
    end
end

function GameTicket:addTicket(type, num)
    local ticket = self.gunTicket[tostring(type)]
    if ticket == nil then
        self.gunTicket[tostring(type)] = 0
        ticket = 0
    end
    self.gunTicket[tostring(type)] = ticket + num
    self:saveData()
end

function GameTicket:subTicket(gunType, num)
    local ticket = self.gunTicket[tostring(gunType)]
    if ticket == nil then
        self.gunTicket[tostring(gunType)] = 0
        ticket = 0
    end
    if ticket >= num then
        self.gunTicket[tostring(gunType)] = ticket - num
    end
    self:saveData()
end

function GameTicket:getTicket(gunType)
    local ticket = self.gunTicket[tostring(gunType)]
    if ticket == nil then
        self.gunTicket[tostring(gunType)] = 0
        ticket = 0
    end
    return ticket
end

function GameTicket:saveData()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        player.gun_ticket = self.gunTicket
    end
    local data = {}
    for i = 1, 5 do
        local ticket = 0
        if next(self.gunTicket) ~= nil and self.gunTicket[tostring(i)] ~= nil then
            ticket = self.gunTicket[tostring(i)]
        end
        local item = {}
        item.Type = i
        item.Num = ticket
        table.insert(data, item)
    end
    GamePacketSender:sendPixelGunStoreTicketData(player.rakssid, json.encode(data))
end